def tokens(s):
    return normalize_arabic2(s).split()

def token_f1(a,b):
    ta = tokens(a); tb=tokens(b)
    set_a = ta
    set_b = tb
    # compute multiset overlap? We'll do simple bag-of-words with counts
    from collections import Counter
    ca, cb = Counter(ta), Counter(tb)
    common = sum((ca & cb).values())
    if len(ta)==0 or len(tb)==0:
        return 0.0
    prec = common/len(tb)
    rec = common/len(ta)
    if prec+rec==0:
        return 0.0
    return 2*prec*rec/(prec+rec), prec, rec, common, len(ta), len(tb)

