def lcs_length(a,b):
    ta = tokens(a)
    tb = tokens(b)
    # dynamic programming
    n, m = len(ta), len(tb)
    dp = [0]*(m+1)
    for i in range(1,n+1):
        prev=0
        for j in range(1,m+1):
            temp=dp[j]
            if ta[i-1]==tb[j-1]:
                dp[j]=prev+1
            else:
                if dp[j]>dp[j-1]:
                    dp[j]=dp[j]
                else:
                    dp[j]=dp[j-1]
            prev=temp
    return dp[m], n, m, ta, tb

